const day = new Date().getDay();
const themes = ($('Fetch Themes from DB').first().json.data);
const dailyTheme = themes[day];
const cricketData = $input.first().json;
const isMatchDay = cricketData?.data?.isMatchDay === true;
const postDate = new Date().toISOString().split('T')[0];
const dayName = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][day];

// Check for forceTheme from manual trigger webhook payload
let forcedTheme = null;
try {
  const webhookJson = $('Manual Generate Trigger').first().json;
  const forceThemeName = webhookJson?.body?.forceTheme || webhookJson?.forceTheme;
  if (forceThemeName) {
    const found = themes.find(t => t.name === forceThemeName);
    if (found) forcedTheme = found;
  }
} catch(e) {
  // Scheduled trigger — no webhook data available
}

const selectedTheme = forcedTheme || dailyTheme;

const items = [
  {
    json: {
      theme_name: selectedTheme.name,
      theme_emoji: selectedTheme.emoji,
      theme_focus: selectedTheme.focus,
      day_of_week: dayName,
      post_id: 'AMGO_' + postDate + '_DAILY',
      post_date: postDate,
      is_match_day: isMatchDay,
      post_type: 'daily'
    }
  }
];

if (isMatchDay && !forcedTheme) {
  const { matchTitle, teams, venue } = cricketData.data;
  items.push({
    json: {
      theme_name: 'Match Day Inspiration',
      theme_emoji: '🏆',
      theme_focus: `${matchTitle} is on today! Match-day content — elite cricket energy, game-day gear, player inspiration. Mention that serious cricketers gear up at AMGO Sports. Reference the match: ${matchTitle} — ${teams} at ${venue}.`,
      day_of_week: dayName,
      post_id: 'AMGO_' + postDate + '_MATCH',
      post_date: postDate,
      is_match_day: true,
      post_type: 'match'
    }
  });
}

return items;

