parameters.jsCode:
const rawText = $input.first().json.text || $input.first().json.message?.content || '';
const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) { parsed = JSON.parse(match[0]); }
  else { throw new Error('Could not parse AI output as JSON: ' + cleaned.substring(0, 200)); }
}
const themeData = $('Select Today Theme').item.json;
return [{ json: { caption: parsed.caption, hashtags: parsed.hashtags, dalle_prompt: parsed.dalle_prompt, alt_text: parsed.alt_text, theme_tag: parsed.theme_tag, full_caption: parsed.caption + '\n\n' + parsed.hashtags, post_id: themeData.post_id, post_date: themeData.post_date, theme_name: themeData.theme_name, theme_emoji: themeData.theme_emoji, day_of_week: themeData.day_of_week, is_match_day: themeData.is_match_day, post_type: themeData.post_type, generated_at: new Date().toISOString() } }];

try {
  const parsed = $('Parse AI Output').item.json;
  const imgbb = $input.first().json;
  return [{ json: { ...parsed, image_url: imgbb?.data?.url || '' } }];
} catch (error) {
  return [{ json: { caption: 'Test Caption', hashtags: '#test', image_url: 'https://i.ibb.co/test/test.png', _error: error.message } }];
}

